import type { Metadata } from "next";
import SettingsClient from "./SettingsClient";

export const metadata: Metadata = {
  title: "設定 · Gunjo Test",
  description:
    "@gunjo/ui で構築したアカウント・ワークスペース設定ハブ（プロフィール、セキュリティ、チーム、通知、お支払い、危険な操作）。",
};

export default function SettingsPage() {
  return <SettingsClient />;
}

"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  Avatar,
  AvatarFallback,
  AvatarImage,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
  Checkbox,
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  EmptyState,
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormGroup,
  FormLabel,
  FormMessage,
  Input,
  PasswordInput,
  RadioGroup,
  RadioGroupItem,
  Select,
  Separator,
  Switch,
  Table,
  Textarea,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  ToastProvider,
  useToast,
} from "@gunjo/ui";
import {
  IconBell,
  IconCreditCard,
  IconLock,
  IconMoon,
  IconSun,
  IconTrash,
  IconUpload,
  IconUser,
  IconUsers,
} from "@tabler/icons-react";

/* -------------------------------------------------------------------------- */
/* Types & constants                                                          */
/* -------------------------------------------------------------------------- */

type SectionId =
  | "profile"
  | "security"
  | "team"
  | "notifications"
  | "billing";

const SECTIONS: { id: SectionId; label: string; icon: React.ReactNode }[] = [
  { id: "profile", label: "プロフィール", icon: <IconUser className="h-4 w-4" /> },
  { id: "security", label: "セキュリティ", icon: <IconLock className="h-4 w-4" /> },
  { id: "team", label: "チーム", icon: <IconUsers className="h-4 w-4" /> },
  {
    id: "notifications",
    label: "通知",
    icon: <IconBell className="h-4 w-4" />,
  },
  {
    id: "billing",
    label: "お支払い",
    icon: <IconCreditCard className="h-4 w-4" />,
  },
];

const WORKSPACE_NAME = "acme-inc";

type Role = "admin" | "editor" | "viewer";

interface Member {
  id: string;
  name: string;
  email: string;
  role: Role;
}

const INITIAL_MEMBERS: Member[] = [
  { id: "1", name: "佐藤 健太", email: "kenta@acme.test", role: "admin" },
  { id: "2", name: "鈴木 大輔", email: "daisuke@acme.test", role: "editor" },
  { id: "3", name: "山田 花子", email: "hanako@acme.test", role: "viewer" },
];

/* -------------------------------------------------------------------------- */
/* Helpers                                                                    */
/* -------------------------------------------------------------------------- */

function initialsOf(name: string) {
  return (
    name
      .split(" ")
      .map((p) => p[0])
      .filter(Boolean)
      .slice(0, 2)
      .join("")
      .toUpperCase() || "?"
  );
}

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/* -------------------------------------------------------------------------- */
/* Dark-mode toggle (lib is class-based: `.dark` on a parent)                 */
/* -------------------------------------------------------------------------- */

function useDarkMode() {
  const [dark, setDark] = React.useState(false);
  React.useEffect(() => {
    document.documentElement.classList.toggle("dark", dark);
  }, [dark]);
  return [dark, setDark] as const;
}

/* ========================================================================== */
/* PROFILE                                                                    */
/* ========================================================================== */

function ProfileSection() {
  const { showToast } = useToast();
  const [name, setName] = React.useState("佐藤 健太");
  const [bio, setBio] = React.useState("数学が好き。Acmeでプロダクトを作っています。");
  // baseline for dirty-tracking
  const baseline = React.useRef({ name, bio });
  const [touched, setTouched] = React.useState(false);

  const nameError =
    touched && name.trim() === "" ? "表示名を入力してください。" : undefined;

  const dirty = name !== baseline.current.name || bio !== baseline.current.bio;

  const onSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setTouched(true);
    if (name.trim() === "") return;
    baseline.current = { name, bio };
    setTouched(false);
    showToast("プロフィールを保存しました。", "success");
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle as="h2">プロフィール</CardTitle>
        <CardDescription>
          この情報はワークスペースのメンバーに表示されます。
        </CardDescription>
      </CardHeader>
      <Form onSubmit={onSubmit} noValidate>
        <CardContent className="flex flex-col gap-6">
          {/* Avatar + change photo */}
          <div className="flex items-center gap-4">
            <Avatar className="h-16 w-16">
              <AvatarImage src="" alt="" />
              <AvatarFallback>{initialsOf(name)}</AvatarFallback>
            </Avatar>
            <div className="flex flex-col gap-1">
              <Button type="button" variant="outline" size="sm">
                <IconUpload className="h-4 w-4" />
                写真を変更
              </Button>
              <p className="text-xs text-muted-foreground">
                JPGまたはPNG、2&nbsp;MBまで。
              </p>
            </div>
          </div>

          <FormGroup>
            <FormField required error={nameError} className="p-0">
              <FormLabel>表示名</FormLabel>
              <FormControl>
                <Input
                  value={name}
                  placeholder="お名前"
                  onChange={(e) => setName(e.target.value)}
                  onBlur={() => setTouched(true)}
                />
              </FormControl>
              <FormMessage />
            </FormField>

            <FormField className="p-0">
              <FormLabel>自己紹介</FormLabel>
              <FormControl>
                <Textarea
                  value={bio}
                  onChange={(e) => setBio(e.target.value)}
                  rows={3}
                />
              </FormControl>
              <FormDescription>
                プロフィールに表示される短い紹介文です。
              </FormDescription>
            </FormField>
          </FormGroup>
        </CardContent>
        <CardFooter className="justify-end">
          <Button type="submit" disabled={!dirty}>
            変更を保存
          </Button>
        </CardFooter>
      </Form>
    </Card>
  );
}

/* ========================================================================== */
/* SECURITY                                                                   */
/* ========================================================================== */

function SecuritySection() {
  const { showToast } = useToast();
  const [current, setCurrent] = React.useState("");
  const [next, setNext] = React.useState("");
  const [confirm, setConfirm] = React.useState("");
  const [submitted, setSubmitted] = React.useState(false);
  const [twoFa, setTwoFa] = React.useState(false);

  const currentError =
    submitted && current === "" ? "現在のパスワードを入力してください。" : undefined;
  const nextError =
    submitted && next.length < 8
      ? "新しいパスワードは8文字以上で入力してください。"
      : undefined;
  const confirmError =
    submitted && confirm !== next ? "パスワードが一致しません。" : undefined;

  const onSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitted(true);
    if (current === "" || next.length < 8 || confirm !== next) return;
    setCurrent("");
    setNext("");
    setConfirm("");
    setSubmitted(false);
    showToast("パスワードを変更しました。", "success");
  };

  return (
    <div className="flex flex-col gap-6">
      <Card>
        <CardHeader>
          <CardTitle as="h2">パスワードの変更</CardTitle>
          <CardDescription>
            8文字以上で設定してください。このデバイスではログインしたままになります。
          </CardDescription>
        </CardHeader>
        <Form onSubmit={onSubmit} noValidate>
          <CardContent>
            <FormGroup>
              <FormField required error={currentError} className="p-0">
                <FormLabel>現在のパスワード</FormLabel>
                <FormControl>
                  <PasswordInput
                    autoComplete="current-password"
                    value={current}
                    onChange={(e) => setCurrent(e.target.value)}
                  />
                </FormControl>
                <FormMessage />
              </FormField>

              <FormField required error={nextError} className="p-0">
                <FormLabel>新しいパスワード</FormLabel>
                <FormControl>
                  <PasswordInput
                    autoComplete="new-password"
                    value={next}
                    onChange={(e) => setNext(e.target.value)}
                  />
                </FormControl>
                {nextError ? (
                  <FormMessage />
                ) : (
                  <FormDescription>8文字以上で入力してください。</FormDescription>
                )}
              </FormField>

              <FormField required error={confirmError} className="p-0">
                <FormLabel>新しいパスワード（確認）</FormLabel>
                <FormControl>
                  <PasswordInput
                    autoComplete="new-password"
                    value={confirm}
                    onChange={(e) => setConfirm(e.target.value)}
                  />
                </FormControl>
                <FormMessage />
              </FormField>
            </FormGroup>
          </CardContent>
          <CardFooter className="justify-end">
            <Button type="submit">パスワードを変更</Button>
          </CardFooter>
        </Form>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle as="h2">2段階認証</CardTitle>
          <CardDescription>
            アカウントのセキュリティをさらに強化します。
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between gap-4">
            <Switch
              checked={twoFa}
              onCheckedChange={(v) => {
                setTwoFa(v);
                showToast(
                  v ? "2段階認証を有効にしました。" : "2段階認証を無効にしました。",
                  v ? "success" : "info"
                );
              }}
              label="認証アプリ"
              description="ログイン時にワンタイムコードの入力を求めます。"
            />
            <Badge variant={twoFa ? "success" : "secondary"}>
              {twoFa ? "オン" : "オフ"}
            </Badge>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

/* ========================================================================== */
/* TEAM                                                                        */
/* ========================================================================== */

function InviteDialog({ onInvite }: { onInvite: (email: string) => void }) {
  const [open, setOpen] = React.useState(false);
  const [email, setEmail] = React.useState("");
  const [submitted, setSubmitted] = React.useState(false);

  const error =
    submitted && !EMAIL_RE.test(email.trim())
      ? "有効なメールアドレスを入力してください。"
      : undefined;

  const submit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitted(true);
    if (!EMAIL_RE.test(email.trim())) return;
    onInvite(email.trim());
    setEmail("");
    setSubmitted(false);
    setOpen(false);
  };

  return (
    <Dialog
      open={open}
      onOpenChange={(o) => {
        setOpen(o);
        if (!o) {
          setEmail("");
          setSubmitted(false);
        }
      }}
    >
      <DialogTrigger asChild>
        <Button size="sm">メンバーを招待</Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>チームメンバーを招待</DialogTitle>
          <DialogDescription>
            ワークスペースへの招待メールが送信されます。
          </DialogDescription>
        </DialogHeader>
        <Form onSubmit={submit} noValidate>
          <FormField required error={error} className="p-0">
            <FormLabel>メールアドレス</FormLabel>
            <FormControl>
              <Input
                type="email"
                placeholder="name@company.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </FormControl>
            <FormMessage />
          </FormField>
          <DialogFooter>
            <DialogClose asChild>
              <Button type="button" variant="outline">
                キャンセル
              </Button>
            </DialogClose>
            <Button type="submit">招待を送信</Button>
          </DialogFooter>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

function TeamSection() {
  const { showToast } = useToast();
  const [members, setMembers] = React.useState<Member[]>(INITIAL_MEMBERS);

  const setRole = (id: string, role: Role) =>
    setMembers((m) => m.map((x) => (x.id === id ? { ...x, role } : x)));

  const remove = (id: string) => {
    setMembers((m) => m.filter((x) => x.id !== id));
    showToast("メンバーを削除しました。", "info");
  };

  const invite = (email: string) => {
    const name = email.split("@")[0].replace(/\W+/g, " ").trim() || email;
    setMembers((m) => [
      ...m,
      { id: String(Date.now()), name, email, role: "viewer" },
    ]);
    showToast(`${email} に招待を送信しました。`, "success");
  };

  return (
    <Card>
      <CardHeader className="flex-row items-start justify-between gap-4 space-y-0">
        <div className="space-y-1.5">
          <CardTitle as="h2">チームメンバー</CardTitle>
          <CardDescription>
            このワークスペースにアクセスできるメンバーを管理します。
          </CardDescription>
        </div>
        <InviteDialog onInvite={invite} />
      </CardHeader>
      <CardContent>
        {members.length === 0 ? (
          <EmptyState
            headingLevel={3}
            title="メンバーがいません"
            description="このワークスペースで協働するメンバーを招待しましょう。"
          />
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>名前</TableHead>
                <TableHead>メールアドレス</TableHead>
                <TableHead className="w-40">権限</TableHead>
                <TableHead className="w-20 text-right">
                  <span className="sr-only">操作</span>
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {members.map((m) => (
                <TableRow key={m.id}>
                  <TableCell className="font-medium text-foreground">
                    <div className="flex items-center gap-2">
                      <Avatar className="h-7 w-7">
                        <AvatarFallback className="text-xs">
                          {initialsOf(m.name)}
                        </AvatarFallback>
                      </Avatar>
                      {m.name}
                    </div>
                  </TableCell>
                  <TableCell className="text-muted-foreground">
                    {m.email}
                  </TableCell>
                  <TableCell>
                    <Select
                      aria-label={`${m.name}さんの権限`}
                      value={m.role}
                      onChange={(e) =>
                        setRole(m.id, e.target.value as Role)
                      }
                    >
                      <option value="admin">管理者</option>
                      <option value="editor">編集者</option>
                      <option value="viewer">閲覧者</option>
                    </Select>
                  </TableCell>
                  <TableCell className="text-right">
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      aria-label={`${m.name}さんを削除`}
                      onClick={() => remove(m.id)}
                    >
                      <IconTrash className="h-4 w-4 text-destructive" />
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>
    </Card>
  );
}

/* ========================================================================== */
/* NOTIFICATIONS                                                               */
/* ========================================================================== */

type Channel = "emailComments" | "emailSecurity" | "pushMentions";

function NotificationsSection() {
  const { showToast } = useToast();
  const [prefs, setPrefs] = React.useState<Record<Channel, boolean>>({
    emailComments: true,
    emailSecurity: true,
    pushMentions: false,
  });
  const [frequency, setFrequency] = React.useState("daily");

  const toggle = (k: Channel) =>
    setPrefs((p) => ({ ...p, [k]: !p[k] }));

  return (
    <Card>
      <CardHeader>
        <CardTitle as="h2">通知</CardTitle>
        <CardDescription>受け取りたい通知を選んでください。</CardDescription>
      </CardHeader>
      <CardContent className="flex flex-col gap-6">
        <fieldset className="flex flex-col gap-4">
          <legend className="text-sm font-medium text-foreground">
            メール
          </legend>
          <Switch
            checked={prefs.emailComments}
            onCheckedChange={() => toggle("emailComments")}
            label="コメントと返信"
            description="自分宛てに返信があったとき。"
          />
          <Switch
            checked={prefs.emailSecurity}
            onCheckedChange={() => toggle("emailSecurity")}
            label="セキュリティ通知"
            description="ログインやパスワードの変更があったとき。"
          />
        </fieldset>

        <Separator />

        <fieldset className="flex flex-col gap-4">
          <legend className="text-sm font-medium text-foreground">プッシュ</legend>
          <Checkbox
            checked={prefs.pushMentions}
            onCheckedChange={() => toggle("pushMentions")}
            label="メンション"
            description="@メンションされたときにプッシュ通知します。"
          />
        </fieldset>

        <Separator />

        <fieldset className="flex flex-col gap-3">
          <legend className="text-sm font-medium text-foreground">
            ダイジェストの頻度
          </legend>
          <RadioGroup
            value={frequency}
            onValueChange={setFrequency}
            aria-label="ダイジェストの頻度"
          >
            {[
              { v: "realtime", l: "リアルタイム" },
              { v: "daily", l: "毎日" },
              { v: "weekly", l: "毎週" },
            ].map(({ v, l }) => (
              <label
                key={v}
                className="flex cursor-pointer items-center gap-2 text-sm"
              >
                <RadioGroupItem value={v} aria-label={l} />
                {l}
              </label>
            ))}
          </RadioGroup>
        </fieldset>
      </CardContent>
      <CardFooter className="justify-end">
        <Button
          type="button"
          onClick={() => showToast("通知設定を保存しました。", "success")}
        >
          設定を保存
        </Button>
      </CardFooter>
    </Card>
  );
}

/* ========================================================================== */
/* BILLING                                                                     */
/* ========================================================================== */

const INVOICES = [
  { id: "INV-0007", date: "2026年6月1日", amount: "¥7,200", status: "支払済み" },
  { id: "INV-0006", date: "2026年5月1日", amount: "¥7,200", status: "支払済み" },
  { id: "INV-0005", date: "2026年4月1日", amount: "¥7,200", status: "支払済み" },
];

function BillingSection() {
  return (
    <div className="flex flex-col gap-6">
      <Card>
        <CardHeader className="flex-row items-start justify-between gap-4 space-y-0">
          <div className="space-y-1.5">
            <CardTitle as="h2">現在のプラン</CardTitle>
            <CardDescription>毎月請求 · 次回更新 2026年7月1日</CardDescription>
          </div>
          <Badge variant="info">チーム</Badge>
        </CardHeader>
        <CardContent className="flex flex-wrap items-end justify-between gap-4">
          <div>
            <p className="text-3xl font-semibold text-foreground">
              ¥7,200
              <span className="text-base font-normal text-muted-foreground">
                {" "}
                / 月
              </span>
            </p>
            <p className="text-sm text-muted-foreground">
              3シート · プロジェクト無制限
            </p>
          </div>
          <Button variant="outline" size="sm">
            プランを変更
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle as="h2">お支払い方法</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between gap-4 rounded-lg border border-border p-4">
            <div className="flex items-center gap-3">
              <IconCreditCard className="h-5 w-5 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium text-foreground">
                  Visa 下4桁 4242
                </p>
                <p className="text-xs text-muted-foreground">有効期限 08/28</p>
