/* ========================================================================== */
/* DANGER ZONE                                                                 */
/* ========================================================================== */

function DangerZone() {
  const { showToast } = useToast();
  const [open, setOpen] = React.useState(false);
  const [confirmText, setConfirmText] = React.useState("");
  const matches = confirmText === WORKSPACE_NAME;

  return (
    <Card className="border-destructive-border">
      <CardHeader>
        <CardTitle as="h2" className="text-destructive">
          危険な操作
        </CardTitle>
        <CardDescription>
          ワークスペースの削除は完全に行われ、元に戻すことはできません。
        </CardDescription>
      </CardHeader>
      <CardContent>
        <Dialog
          open={open}
          onOpenChange={(o) => {
            setOpen(o);
            if (!o) setConfirmText("");
          }}
        >
          <DialogTrigger asChild>
            <Button variant="destructive">
              <IconTrash className="h-4 w-4" />
              ワークスペースを削除
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>ワークスペースを削除</DialogTitle>
              <DialogDescription>
                <strong className="text-foreground">{WORKSPACE_NAME}</strong>{" "}
                ワークスペースとそのすべてのデータが完全に削除されます。
              </DialogDescription>
            </DialogHeader>
            <Alert variant="destructive">
              <AlertDescription>
                この操作は元に戻せません。
              </AlertDescription>
            </Alert>
            <FormField className="p-0">
              <FormLabel htmlFor="confirm-delete">
                確認のため <span className="font-mono">{WORKSPACE_NAME}</span>{" "}
                と入力してください
              </FormLabel>
              <FormControl>
                <Input
                  id="confirm-delete"
                  value={confirmText}
                  autoComplete="off"
                  onChange={(e) => setConfirmText(e.target.value)}
                />
              </FormControl>
            </FormField>
            <DialogFooter>
              <DialogClose asChild>
                <Button type="button" variant="outline">
                  キャンセル
                </Button>
              </DialogClose>
              <Button
                type="button"
                variant="destructive"
                disabled={!matches}
                onClick={() => {
                  setOpen(false);
                  setConfirmText("");
                  showToast("ワークスペースを削除しました。", "error");
                }}
              >
                このワークスペースを削除
              </Button>
            </DialogFooter>
          </DialogContent>
